+    expect(canonicalizePathForSecurity("/API/channels//nostr/default/profile/")).toEqual({
+      path: "/api/channels/nostr/default/profile",
+      malformedEncoding: false,
+      rawNormalizedPath: "/api/channels/nostr/default/profile",
